.carousel-controls {
  position: absolute;
  top: 50%;
  width: 100%;
  display: flex;
  justify-content: space-between;
}

.carousel-controls button {
  background: rgba(44, 44, 44, 0.5);
  color: white;
  border: none;
  font-size: 1rem;
  cursor: pointer;
  border-radius: 50%;
  padding: 0.5rem 1rem;
  position: relative;
}

/* === Secciones de historias === */
.stories-section {
  margin: 2rem;
  align-items: center;
}

.stories-section h2 {
  margin-bottom: 1rem;
  margin-left: 260px; /* leve desplazamiento visual para armonía */
  font-size: 1.5rem;
}

.stories-section {
  margin: 3rem auto;
  max-width: 90%; /* limita el ancho total para que el título y libros estén alineados */
}

.scroll-container {
  display: flex;
  flex-wrap: wrap; /* permite que los libros salten a otra línea si no caben */
  justify-content: center;
  gap: 1rem;
  padding: 10px;
  overflow-x: auto; /* mantiene el scroll si hay demasiados */
  box-sizing: border-box;
  padding: 0.8rem 10px 1rem 10px;
}

.story-card {
  flex: 1 1 150px; /*  permite adaptación dinámica */
  max-width: 180px; /*  evita que crezcan demasiado */
  min-width: 140px; /*  evita que se deformen en zoom alto */
  background: white;
  border-radius: var(--radius);
  box-shadow: 0 2px 5px rgba(225, 228, 87, 0.1);
  text-align: center;
  transition: var(--transition);
}

.story-card img {
  width: 100%;
  height: auto;
  border-radius: var(--radius) var(--radius) 0 0;
  object-fit: cover;
}

.story-card:hover {
  transform: scale(1.05);
}

.story-card img {
  width: 100%;
  border-radius: var(--radius) var(--radius) 0 0;
  height: 220px;
  object-fit: cover;
}
.leer_story {
  margin-top: 10px;
  margin-bottom: 10px;
  border: none;
  border-radius: 15px; /* 🔸 más redondo */
  padding: 10px 25px;
  background-color: #5fa55a;
  color: rgb(255, 255, 255);
  font-weight: 600;
  cursor: pointer;
  transition: background-color 0.3s ease, transform 0.2s ease;
}
.leer_story:hover {
  background-color: #88cc50; /* color cálido al pasar el cursor */
  transform: scale(1.05);
}

.navbar:hover .dropbtn {
  color: var(--text-bright);
}
.story-card h3 {
  margin: 0.5rem 0;
  font-size: 1rem;
  color: var(--text-dark);
}
.scroll-btn {
  position: absolute;
  top: 35%;
  background: rgba(255,255,255,0.8);
  border: none;
  font-size: 1.5rem;
  cursor: pointer;
  border-radius: 50%;
  padding: 0.3rem 0.6rem;
  transition: var(--transition);
}

.scroll-btn:hover {
  background: var(--orange);
  color: rgb(201, 13, 13);
}

.scroll-btn.left { left: -5px; }
.scroll-btn.right { right: -5px; }

/* === Historia destacada === */
.featured-story {
  display: flex;
  margin: 3rem 2rem;
  background: white;
  border-radius: var(--radius);
  overflow: hidden;
}

.featured-story img {
  width: 50%;
  object-fit: cover;
}

.featured-story .info {
  padding: 2rem;
}

/* === Footer === */
footer {
  background: #ffffff;
  text-align: center;
  padding: 2rem;
  font-size: 0.9rem;
  color: #012464;
}

.footer-links {
  display: flex;
  justify-content: center;
  gap: 1.5rem;
  flex-wrap: wrap;
  margin-bottom: 0.8rem;
}

.footer-links a {
  color: #444;
  text-decoration: none;
}

.footer-links a:hover {
  text-decoration: underline;
}

.scroll-container {
  display: flex;
  justify-content: center; /* Centra horizontalmente */
  align-items: center;     /* Centra verticalmente */
  flex-wrap: wrap;         /* Para que salten de línea si hay muchas */
  gap: 1.5rem;             /* Espaciado entre tarjetas */
  padding: 20px;
}

.theme-color {
  background: #99d6e0;
  border: none;
  color: var(--text-light);
  font-weight: 100;
  cursor: pointer;
}
